import { Injectable, computed, signal } from '@angular/core';
import { Router } from '@angular/router';
import { inject } from '@angular/core';
import { AuthUser, Role } from './models';

const STORAGE_KEY = 'user';

@Injectable({ providedIn: 'root' })
export class AuthService {
  private readonly router = inject(Router);

  readonly user = signal<AuthUser | null>(this.restore());
  readonly isAuthenticated = computed(() => this.user() !== null);
  readonly isAdmin = computed(() => this.user()?.role === 'ADMIN');

  private restore(): AuthUser | null {
    try {
      const raw = localStorage.getItem(STORAGE_KEY);
      return raw ? (JSON.parse(raw) as AuthUser) : null;
    } catch {
      return null;
    }
  }

  private persist(user: AuthUser): void {
    const token = 'mock-jwt-' + user.id;
    localStorage.setItem('token', token);
    localStorage.setItem('access_token', token);
    localStorage.setItem('isAuthenticated', 'true');
    localStorage.setItem(STORAGE_KEY, JSON.stringify(user));
    this.user.set(user);
  }

  /** Mockup login: accepts any well-formed credentials. */
  login(email: string, role: Role = 'USER'): void {
    const name = email.split('@')[0].replace(/[._-]/g, ' ') || 'Demo User';
    this.persist({
      id: 'u-' + Math.abs(hash(email)),
      name: titleCase(name),
      email,
      role,
    });
  }

  signup(name: string, email: string): void {
    this.persist({ id: 'u-' + Math.abs(hash(email)), name, email, role: 'USER' });
  }

  /** Demo Mode bypass — signs in as an admin and jumps to the dashboard. */
  demoLogin(): void {
    this.persist({
      id: 'demo-admin',
      name: 'Demo Admin',
      email: 'demo.admin@cloudline.crm',
      role: 'ADMIN',
    });
    this.router.navigate(['/dashboard']);
  }

  logout(): void {
    ['token', 'access_token', 'isAuthenticated', STORAGE_KEY].forEach((k) =>
      localStorage.removeItem(k),
    );
    this.user.set(null);
    this.router.navigate(['/login']);
  }
}

function hash(value: string): number {
  let h = 0;
  for (let i = 0; i < value.length; i++) {
    h = (h << 5) - h + value.charCodeAt(i);
    h |= 0;
  }
  return h;
}

function titleCase(value: string): string {
  return value.replace(/\b\w/g, (c) => c.toUpperCase());
}
